import React, { useState } from 'react';
import styled from 'styled-components';
import { motion, AnimatePresence } from 'framer-motion';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import PERatioTrendGraph from '../components/PERatioTrendGraph';
import CombinedKMeansClustering from '../components/CombinedKMeansClustering';

const PortfolioContainer = styled.div`
  max-width: 1400px;
  margin: 0 auto;
  padding: 1rem 0;
`;

const PageHeader = styled(motion.div)`
  margin-bottom: 4rem;

  h1 {
    font-size: 3.5rem;
    font-weight: 900;
    letter-spacing: -2px;
    margin-bottom: 1rem;
    background: ${props => props.theme.colors.accentPrimary};
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
  }

  p {
    color: ${props => props.theme.colors.textSecondary};
    font-size: 1.1rem;
    max-width: 600px;
  }
`;

const GlassCard = styled(motion.div)`
  background: ${props => props.theme.colors.cardBackground};
  border-radius: ${props => props.theme.borderRadius.large};
  border: 1px solid ${props => props.theme.colors.border};
  backdrop-filter: blur(12px);
  box-shadow: ${props => props.theme.shadows.card};
  position: relative;
  overflow: hidden;
`;

const SummarySection = styled(GlassCard)`
  padding: 3rem;
  margin-bottom: 4rem;
  display: grid;
  grid-template-columns: 1fr 2fr;
  gap: 4rem;

  @media (max-width: 1024px) {
    grid-template-columns: 1fr;
    gap: 2rem;
  }
`;

const PortfolioValueDisplay = styled.div`
  .label {
    font-size: 0.9rem;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    color: ${props => props.theme.colors.textSecondary};
    font-weight: 600;
    margin-bottom: 0.5rem;
  }

  .value {
    font-size: 4rem;
    font-weight: 900;
    letter-spacing: -2px;
    color: ${props => props.theme.colors.textPrimary};
    font-family: 'JetBrains Mono', monospace;
  }

  .change {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    font-size: 1.1rem;
    font-weight: 700;
    padding: 0.4rem 1rem;
    border-radius: 10px;
    margin-top: 1rem;

    &.positive {
      background: ${props => props.theme.colors.success}15;
      color: ${props => props.theme.colors.success};
    }

    &.negative {
      background: ${props => props.theme.colors.danger}15;
      color: ${props => props.theme.colors.danger};
    }
  }
`;

const AnalyticsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 2rem;

  @media (max-width: 768px) {
    grid-template-columns: 1fr;
  }
`;

const SectorSection = styled.div`
  margin-bottom: 4rem;
`;

const SectorHeader = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 2rem;

  h2 {
    font-size: 1.8rem;
    font-weight: 800;
    letter-spacing: -0.5px;
    text-transform: capitalize;
  }
`;

const StockGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1.5rem;

  @media (max-width: 1100px) {
    grid-template-columns: repeat(2, 1fr);
  }

  @media (max-width: 640px) {
    grid-template-columns: 1fr;
  }
`;

const StockCard = styled(GlassCard)`
  padding: 1.5rem;
  transition: ${props => props.theme.transitions.default};
  cursor: pointer;

  &:hover {
    transform: translateY(-5px);
    border-color: ${props => props.theme.colors.info}30;
    background: rgba(255, 255, 255, 0.05);
  }

  .header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    margin-bottom: 1rem;
  }

  .symbol {
    font-size: 1.2rem;
    font-weight: 800;
    color: ${props => props.theme.colors.info};
  }

  .name {
    font-size: 0.9rem;
    color: ${props => props.theme.colors.textSecondary};
    font-weight: 500;
  }
`;

const RemoveButton = styled.button`
  background: ${props => props.theme.colors.danger}15;
  color: ${props => props.theme.colors.danger};
  border: 1px solid ${props => props.theme.colors.danger}30;
  padding: 0.4rem 0.8rem;
  border-radius: 8px;
  font-size: 0.8rem;
  font-weight: 700;
  cursor: pointer;
  transition: ${props => props.theme.transitions.fast};

  &:hover {
    background: ${props => props.theme.colors.danger};
    color: white;
  }
`;

const SectorStocksGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 1.5rem;
`;

const SectorsContainer = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 1.5rem;
  margin-top: 2rem;
`;

const SectorCard = styled(motion.div)`
  background: ${props => props.theme.colors.cardBackground};
  border-radius: ${props => props.theme.borderRadius.large};
  padding: 2.5rem;
  border: 1px solid ${props => props.theme.colors.border};
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  transition: ${props => props.theme.transitions.default};
  cursor: pointer;
  position: relative;
  overflow: hidden;

  &:hover {
    transform: translateY(-8px);
    border-color: rgba(255, 255, 255, 0.2);
    background: rgba(255, 255, 255, 0.08);
    box-shadow: ${props => props.theme.shadows.glow};
  }
`;

const SectorIcon = styled.div`
  font-size: 3rem;
  margin-bottom: 1rem;
`;

const SectorCardTitle = styled.h3`
  font-size: 1.5rem;
  color: ${props => props.theme.colors.textPrimary};
  margin: 0 0 1rem 0;
  text-transform: capitalize;
  font-weight: 700;
`;

const SectorCardStats = styled.div`
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
  width: 100%;
  margin-top: 1rem;
`;

const SectorStatItem = styled.div`
  text-align: center;
`;

const SectorStatLabel = styled.div`
  font-size: 0.7rem;
  color: #999;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  margin-bottom: 0.3rem;
`;

const SectorStatValue = styled.div`
  font-size: 1.2rem;
  font-weight: 700;
  color: #fff;
`;

const SectorCardButton = styled.button`
  width: 100%;
  background: ${props => props.theme.colors.accentPrimary};
  border: none;
  color: #000;
  padding: 0.8rem;
  border-radius: ${props => props.theme.borderRadius.medium};
  cursor: pointer;
  font-weight: 700;
  margin-top: 1.5rem;
  transition: ${props => props.theme.transitions.default};

  &:hover {
    transform: translateY(-2px);
    box-shadow: ${props => props.theme.shadows.glow};
    opacity: 0.9;
  }
`;

const NewsletterSection = styled(motion.div)`
  margin-top: 4rem;
  padding: 3rem;
  background: ${props => props.theme.colors.cardBackground};
  border-radius: ${props => props.theme.borderRadius.large};
  border: 1px solid ${props => props.theme.colors.border};
  text-align: center;
  backdrop-filter: blur(10px);
`;

const NewsletterTitle = styled.h2`
  font-size: 2.2rem;
  margin-bottom: 1rem;
  background: ${props => props.theme.colors.accentPrimary};
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  font-weight: 800;
`;

const NewsletterButton = styled.button`
  background: ${props => props.theme.colors.accentPrimary};
  border: none;
  color: #000;
  padding: 1rem 2.5rem;
  border-radius: 30px;
  font-size: 1.1rem;
  font-weight: 800;
  cursor: pointer;
  transition: all 0.3s ease;
  box-shadow: ${props => props.theme.shadows.glow};

  &:hover {
    transform: scale(1.05);
    filter: brightness(1.1);
  }
`;

const PaymentModal = styled(motion.div)`
  position: fixed;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 450px;
  background: #1a1a1a;
  padding: 2.5rem;
  border-radius: 20px;
  border: 1px solid rgba(255,255,255,0.1);
  z-index: 1001;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
`;

const Overlay = styled(motion.div)`
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0,0,0,0.8);
  z-index: 1000;
  backdrop-filter: blur(5px);
`;

const PaymentForm = styled.form`
  display: flex;
  flex-direction: column;
  gap: 1.2rem;
  margin-top: 1.5rem;
`;

const PaymentInput = styled.input`
  background: rgba(255,255,255,0.05);
  border: 1px solid rgba(255,255,255,0.1);
  padding: 1rem;
  border-radius: 10px;
  color: white;
  font-size: 1rem;

  &:focus {
    outline: none;
    border-color: #4facfe;
  }
`;

const Portfolio: React.FC = () => {
  const navigate = useNavigate();
  const { user, portfolio, portfolioBySector, removeFromPortfolio } = useAuth();
  const [expandedSymbol, setExpandedSymbol] = useState<string | null>(null);
  const [showPayment, setShowPayment] = useState(false);
  const [paymentData, setPaymentData] = useState({ card: '', expiry: '', cvv: '' });
  const [isProcessing, setIsProcessing] = useState(false);

  const handlePayment = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);
    try {
      // First subscribe
      await fetch('/api/auth/newsletter/subscribe/', {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('access_token')}`
        },
        body: JSON.stringify({ email: user?.email })
      });

      // Then process payment
      await fetch('/api/auth/payments/dummy/', {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('access_token')}`
        },
        body: JSON.stringify({
          amount: 9.99,
          card_number: paymentData.card,
          expiry: paymentData.expiry,
          cvv: paymentData.cvv
        })
      });

      alert('Successfully subscribed! Thank you for your payment.');
      setShowPayment(false);
    } catch (err) {
      alert('Payment failed. Please try again.');
    } finally {
      setIsProcessing(false);
    }
  };

  const totalValue = portfolio.reduce((total, item) => {
    return total + item.price;
  }, 0);

  const totalChange = portfolio.reduce((total, item) => {
    return total + item.change;
  }, 0);

  const avgChange = portfolio.length > 0 ? (totalChange / portfolio.length).toFixed(2) : '0.00';
  const isPositive = parseFloat(avgChange) >= 0;

  const SECTOR_ICONS: { [key: string]: string } = {
    'it': '💻',
    'banking': '🏦',
    'automobile': '🚗',
    'energy': '⚡',
    'pharma': '💊',
    'fmcg': '🛒',
    'metals': '⛏️',
    'finance': '💰',
    'hospitality': '🏨',
    'realty': '🏢'
  };

  return (
    <PortfolioContainer>
      <PageHeader
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8 }}
      >
        <h1>Institutional Portfolio</h1>
        <p>Advanced asset tracking and risk analysis. Zeus monitors your holdings with institutional-grade precision.</p>
      </PageHeader>

      <SummarySection
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8, delay: 0.2 }}
      >
        <PortfolioValueDisplay>
          <div className="label">Total Portfolio Value</div>
          <div className="value">${totalValue.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</div>
          <div className={`change ${isPositive ? 'positive' : 'negative'}`}>
            {isPositive ? '▲' : '▼'} {Math.abs(parseFloat(avgChange))}% Average Return
          </div>
        </PortfolioValueDisplay>
        <AnalyticsGrid>
          <div style={{ height: '100%', minHeight: '200px', background: 'rgba(255,255,255,0.02)', borderRadius: '20px', border: '1px solid rgba(255,255,255,0.05)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <span style={{ color: '#94a3b8', fontSize: '0.9rem' }}>Allocation Heatmap</span>
          </div>
          <div style={{ height: '100%', minHeight: '200px', background: 'rgba(255,255,255,0.02)', borderRadius: '20px', border: '1px solid rgba(255,255,255,0.05)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <span style={{ color: '#94a3b8', fontSize: '0.9rem' }}>Risk Metrics</span>
          </div>
        </AnalyticsGrid>
      </SummarySection>

      <AnalyticsGrid style={{ marginBottom: '4rem' }}>
        <GlassCard style={{ padding: '2rem' }}>
          <h3 style={{ marginBottom: '1.5rem', fontSize: '1.2rem' }}>P/E Ratio Distribution</h3>
          <PERatioGraph stocks={portfolio} />
        </GlassCard>
        <GlassCard style={{ padding: '2rem' }}>
          <h3 style={{ marginBottom: '1.5rem', fontSize: '1.2rem' }}>Cluster Analysis</h3>
          <CombinedKMeansClustering stocks={portfolio} />
        </GlassCard>
      </AnalyticsGrid>

      {Object.keys(portfolioBySector).length > 0 ? (
        Object.entries(portfolioBySector).map(([sector, stocks]) => (
          <SectorSection key={sector}>
            <SectorHeader>
              <h2>{SECTOR_ICONS[sector.toLowerCase()] || '📁'} {sector} Sector</h2>
              <div style={{ fontSize: '0.9rem', color: '#94a3b8', fontWeight: 600 }}>
                {stocks.length} Holdings
              </div>
            </SectorHeader>
            <StockGrid>
              {stocks.map((stock) => (
                <StockCard key={stock.symbol} whileHover={{ y: -5 }}>
                  <div className="header">
                    <div>
                      <div className="symbol">{stock.symbol}</div>
                      <div className="name">{stock.name}</div>
                    </div>
                    <RemoveButton onClick={() => removeFromPortfolio(stock.symbol)}>
                      Remove
                    </RemoveButton>
                  </div>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginTop: '1rem' }}>
                    <div>
                      <div style={{ fontSize: '0.75rem', color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '1px', marginBottom: '4px' }}>Last Price</div>
                      <div style={{ fontSize: '1.2rem', fontWeight: 800 }}>${stock.price.toLocaleString()}</div>
                    </div>
                    <div style={{ textAlign: 'right' }}>
                      <div style={{ 
                        fontSize: '0.9rem', 
                        fontWeight: 700, 
                        color: stock.change >= 0 ? '#10b981' : '#ef4444' 
                      }}>
                        {stock.change >= 0 ? '+' : ''}{stock.change.toFixed(2)}%
                      </div>
                    </div>
                  </div>
                </StockCard>
              ))}
            </StockGrid>
          </SectorSection>
        ))
      ) : (
        <GlassCard style={{ padding: '4rem', textAlign: 'center' }}>
          <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>📊</div>
          <h3 style={{ fontSize: '1.5rem', marginBottom: '0.5rem' }}>Your portfolio is empty</h3>
          <p style={{ color: '#94a3b8' }}>Start adding stocks to track your performance and get deep analytics.</p>
          <button 
            onClick={() => navigate('/stocks')}
            style={{ 
              marginTop: '2rem',
              padding: '0.8rem 2rem',
              background: 'linear-gradient(135deg, #38bdf8 0%, #3b82f6 100%)',
              border: 'none',
              borderRadius: '12px',
              color: 'white',
              fontWeight: 700,
              cursor: 'pointer'
            }}
          >
            Explore Stocks
          </button>
        </GlassCard>
      )}

      <NewsletterSection
        initial={{ opacity: 0, y: 30 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true }}
      >
        <NewsletterTitle>Premium Intelligence</NewsletterTitle>
        <p style={{ color: '#94a3b8', marginBottom: '2rem', maxWidth: '500px', margin: '0 auto 2rem' }}>
          Get exclusive market reports and AI-driven trade signals delivered to your inbox weekly.
        </p>
        <NewsletterButton onClick={() => setShowPayment(true)}>
          Subscribe to Zeus Premium
        </NewsletterButton>
      </NewsletterSection>

      <AnimatePresence>
        {showPayment && (
          <>
            <Overlay
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setShowPayment(false)}
            />
            <PaymentModal
              initial={{ opacity: 0, scale: 0.9, y: '-50%', x: '-50%' }}
              animate={{ opacity: 1, scale: 1, y: '-50%', x: '-50%' }}
              exit={{ opacity: 0, scale: 0.9, y: '-50%', x: '-50%' }}
            >
              <h2 style={{ fontSize: '1.8rem', fontWeight: 800, marginBottom: '0.5rem' }}>Zeus Premium</h2>
              <p style={{ color: '#94a3b8', marginBottom: '2rem' }}>$9.99 / month • Cancel anytime</p>
              <PaymentForm onSubmit={handlePayment}>
                <PaymentInput 
                  placeholder="Card Number" 
                  value={paymentData.card}
                  onChange={e => setPaymentData({...paymentData, card: e.target.value})}
                  required
                />
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                  <PaymentInput 
                    placeholder="MM/YY" 
                    value={paymentData.expiry}
                    onChange={e => setPaymentData({...paymentData, expiry: e.target.value})}
                    required
                  />
                  <PaymentInput 
                    placeholder="CVV" 
                    value={paymentData.cvv}
                    onChange={e => setPaymentData({...paymentData, cvv: e.target.value})}
                    required
                  />
                </div>
                <NewsletterButton 
                  type="submit" 
                  disabled={isProcessing}
                  style={{ width: '100%', marginTop: '1rem' }}
                >
                  {isProcessing ? 'Processing...' : 'Complete Payment'}
                </NewsletterButton>
              </PaymentForm>
              <button 
                onClick={() => setShowPayment(false)}
                style={{ 
                  width: '100%', 
                  background: 'transparent', 
                  border: 'none', 
                  color: '#94a3b8', 
                  marginTop: '1rem',
                  cursor: 'pointer',
                  fontSize: '0.9rem'
                }}
              >
                Cancel
              </button>
            </PaymentModal>
          </>
        )}
      </AnimatePresence>
    </PortfolioContainer>
  );
};

export default Portfolio;
